from agent import *from models.products import *import redef run(context, session):    session.sessionbreakers = [SessionBreak(max_requests=6000)]    session.queue(Request('https://www.doblu.com/category/blu-ray-reviews/'), process_category, dict(cat='Films|Blu-ray'))def process_category(data, context, session):    cats = data.xpath('//li[contains(@class, "object-category")][a[contains(., "Blu-ray")]]/ul/li/a')    for cat in cats:        name = cat.xpath('span/text()').string()        url = cat.xpath('@href').string()        session.queue(Request(url), process_revlist, dict(cat=context['cat']+'|'+name))def process_revlist(data, context, session):    revs = data.xpath('//div[contains(@class, "card-review")]')    for rev in revs:        title = rev.xpath('.//h6/text()').string()        url = rev.xpath('div/a/@href').string()        session.queue(Request(url), process_review, dict(context, title=title, url=url))    next_url = data.xpath('//link[@rel="next"]/@href').string()    if next_url:        session.queue(Request(next_url), process_revlist, dict(context))def process_review(data, context, session):    product = Product()    product.name = data.xpath('//h5[@class="review-title"]/text()').string() or context['title'].split(' Blu-ray')[0].split(' Review')[0].split(' review')[0]    product.url = context['url']    product.category = context['cat']    product.ssid = data.xpath('//body[contains(@class, "postid-")]/@class').string().split('postid-')[-1].split()[0]    review = Review()    review.title = context['title']    review.type = 'pro'    review.url = context['url']    review.ssid = product.ssid    date = data.xpath('//meta[@property="article:published_time" or @property="og:updated_time"]/@content').string()    if date:        review.date = date.split('T')[0]    author = data.xpath('//div[contains(@class, "box-author")]').first()    if author:        author_name = author.xpath('.//h6//text()').string().strip()        author_url = author.xpath('.//a/@href').string()        author_ssid = author_url.split('/')[-2]        review.authors.append(Person(name=author_name, ssid=author_ssid))    grade_overall = data.xpath('//span[@class="review-total-box"]/text()').string()    if not grade_overall:        grade_overall = data.xpath('count(//p[strong[@class="rating"][contains(., "Movie")]]//img[@alt="★"])') or data.xpath('//p[strong[@class="rating"][contains(., "Movie")]]//img/@title').string()    if not grade_overall:        grade_overall = data.xpath('//p[contains(., "rating=") and contains(., "label=Movie")]//text()').string(multiple=True)    if grade_overall:        grade_overall = str(grade_overall).split('rating=')[-1].split('/')[0]        review.grades.append(Grade(type='overall', value=float(grade_overall), best=5.0))    grades = data.xpath('//ul[@class="review-list"]/li')    if not grades:        grades = data.xpath('//p[strong[@class="rating"] and not(contains(., "Movie"))]')    if not grades:        grades = data.xpath('//p[contains(., "rating=") and not(contains(., "label=Movie"))]')    for grade in grades:        grade_name = grade.xpath('span/text()').string() or grade.xpath('strong/text()').string() or grade.xpath('.//text()').string(multiple=True)        grade_value = grade.xpath('.//div[@class="review-result"]/@style').string() or grade.xpath('count(.//img[@alt="★"])') or grade.xpath('.//img/@title').string() or grade.xpath('.//text()').string(multiple=True)        if grade_name and grade_value:            grade_name = grade_name.split('label=')[-1].split(']')[0]            grade_value = float(str(grade_value).split('rating=')[-1].split('/')[0].split(':', 1)[-1].split('%')[0].split()[0])            if grade_value > 5:                grade_value = grade_value / 20            if product.name.lower().strip() in grade_name.lower().strip():                review.grades.append(Grade(type='overall', value=grade_value, best=5.0))            else:                review.grades.append(Grade(name=grade_name, value=grade_value, best=5.0))    conclusion = data.xpath('//div[@class="review-desc"]/p[last()]//text()').string(multiple=True)    if conclusion:        review.add_property(type='conclusion', value=conclusion)    excerpt = data.xpath('//div[@id="blog"]/p[not(contains(., "luchshie vechnie ssilki") or contains(., "Full disclosure"))][not(.//a[contains(., "subscription-exclusive")])]//text()').string(multiple=True)    if excerpt:        excerpt = re.sub(r'<.*?>|\[(xrr|amazon)[^\]]*\]', '', excerpt).strip()        review.add_property(type="excerpt", value=excerpt)        product.reviews.append(review)        session.emit(product)